// Map each raw item from YOUR source (a Gmail node, an Apps Script mail digest,
// a calendar feed, …) onto the Signal shape POST /triage expects. Edit the field
// mapping to match your source's payload. `external_id` is what makes re-delivery
// idempotent, so map a stable provider id (e.g. the Gmail message id).
return $input.all().map(({ json }) => ({ json: {
  source: 'mail',
  title: json.subject || json.title || '',
  body: json.snippet || json.body || '',
  sender: json.from || json.sender || '',
  external_id: String(json.id || json.message_id || ''),
} })).filter(i => i.json.title);
